"use strict";(()=>{const btn=document.querySelector(".copy-email-btn");if(!btn)return;const emailLink=document.querySelector('a[href^="mailto:"]');if(!emailLink)return;const email=emailLink.href.replace("mailto:","");btn.addEventListener("click",()=>{navigator.clipboard.writeText(email).then(()=>{btn.classList.add("copied"),btn.setAttribute("aria-label","Email copied!"),setTimeout(()=>{btn.classList.remove("copied"),btn.setAttribute("aria-label","Copy email to clipboard")},2e3)})})})(),function(){const $root=document.querySelector("html"),$langToggle=document.querySelector(".lang-toggle"),languages=["en","ru","uk"];$langToggle.addEventListener("click",function(){$root.setAttribute("lang",function(){const currentLanguageIndex=languages.indexOf($root.getAttribute("lang"));return languages[currentLanguageIndex+1]||languages[0]}())},!1)}(),function(){const $readingModeToggle=document.querySelector(".reading-mode-toggle");$readingModeToggle.addEventListener("click",function(){const $page=document.querySelector(".page");$page.classList.toggle("light"),$page.classList.toggle("dark");const isDark=$page.classList.contains("dark");$readingModeToggle.setAttribute("aria-pressed",String(isDark))},!1)}();